SELECT * FROM "{{JSutils.currentSchema()}}".hotacomo002
WHERE acomo002_deleted <> true and acomo002_desc ILIKE '%{{TableCategoria.searchText}}%'
ORDER BY
{{
  ({
    acomo002_desc: 'acomo002_desc',
    acomo002_id: 'acomo002_id'
  }[TableCategoria.sortOrder.column]) || 'acomo002_desc'
}}
{{ TableCategoria.sortOrder.order === 'DESC' ? 'DESC' : 'ASC' }}
LIMIT {{TableCategoria.pageSize}}
OFFSET {{(TableCategoria.pageNo - 1) * TableCategoria.pageSize}};
